<!doctype html><html><head><title>Billing</title><link rel="stylesheet" href="/style.css"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div class="dash"><div class="side"><h2>Karacraft</h2><a href="/dashboard.php">Dashboard</a><a href="/domains.php">Domains</a><a href="/order.php">Order Hosting</a><a href="/billing.php">Billing</a><a href="/support.php">Support</a><a href="/migration.php">Migration</a><a href="/logout.php">Logout</a></div><div class="main"><h1>Billing</h1><table class="table"><tr><th>Invoice</th><th>Description</th><th>Amount</th><th>Status</th><th>Due</th><th>Date</th></tr><?php foreach($st as $r):?><tr><td><?=h($r['invoice_number'])?></td><td><?=h($r['description'])?><br><small><?=h($r['plan'] ?: '')?></small></td><td><?=h($r['currency'])?> <?=h(number_format((float)$r['amount'],2))?></td><td><span class="badge <?=h($r['status'])?>"><?=h($r['status'])?></span></td><td><?=h($r['due_at'] ?: '-')?></td><td><?=h($r['created_at'])?></td></tr><?php endforeach;?></table></div></div></body></html>
